#include <string.h>
#include <stdlib.h>

// Function to convert a number to a hexadecimal string (base 16)
char* toHex(int64_t n) {
    const char* hexDigits = "0123456789ABCDEF";
    char* result = (char*)malloc(16 * sizeof(char)); // Max length for 64-bit number
    int index = 0;
    if (n == 0) {
        result[index++] = '0';
    } else {
        while (n > 0) {
            result[index++] = hexDigits[n % 16];
            n /= 16;
        }
    }
    // Reverse the string to get the correct order
    for (int i = 0; i < index / 2; i++) {
        char temp = result[i];
        result[i] = result[index - 1 - i];
        result[index - 1 - i] = temp;
    }
    result[index] = '\0';
    return result;
}

// Function to convert a number to a base 36 string (digits 0-9 and letters A-Z)
char* toBase36(int64_t n) {
    const char* base36Digits = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    char* result = (char*)malloc(16 * sizeof(char)); // Max length for 64-bit number
    int index = 0;
    if (n == 0) {
        result[index++] = '0';
    } else {
        while (n > 0) {
            result[index++] = base36Digits[n % 36];
            n /= 36;
        }
    }
    // Reverse the string to get the correct order
    for (int i = 0; i < index / 2; i++) {
        char temp = result[i];
        result[i] = result[index - 1 - i];
        result[index - 1 - i] = temp;
    }
    result[index] = '\0';
    return result;
}

