func solve(n: Int64): String {
    int64_t n2 = n * n;
    int64_t n3 = n * n * n;

    char* hexStr = toHex(n2);
    char* base36Str = toBase36(n3);

    // Concatenate the two strings
    char* result = (char*)malloc(strlen(hexStr) + strlen(base36Str) + 1);
    strcpy(result, hexStr);
